62:   // Send local replies via the downstream HTTP filter manager.
63:   // Local replies will not be seen by upstream HTTP filters.
64:   void sendLocalReply(Http::Code code, absl::string_view body,
65:                       const std::function<void(Http::ResponseHeaderMap& headers)>& modify_headers,
66:                       const absl::optional<Grpc::Status::GrpcStatus> grpc_status,
67:                       absl::string_view details) override {
68:     state().decoder_filter_chain_aborted_ = true;
69:     state().encoder_filter_chain_aborted_ = true;
70:     state().encoder_filter_chain_complete_ = true;
71:     state().observed_encode_end_stream_ = true;
72:     // TODO(alyssawilk) this should be done through the router to play well with hedging.
73:     upstream_request_.parent_.callbacks()->sendLocalReply(code, body, modify_headers, grpc_status,
74:                                                           details);
75:   }
76:   void executeLocalReplyIfPrepared() override {}
