80: UpstreamRequest::UpstreamRequest(RouterFilterInterface& parent,
81:                                  std::unique_ptr<GenericConnPool>&& conn_pool,
82:                                  bool can_send_early_data, bool can_use_http3,
83:                                  bool enable_half_close)
84:     : parent_(parent), conn_pool_(std::move(conn_pool)),
85:       stream_info_(parent_.callbacks()->dispatcher().timeSource(), nullptr,
86:                    StreamInfo::FilterState::LifeSpan::FilterChain),
87:       start_time_(parent_.callbacks()->dispatcher().timeSource().monotonicTime()),
88:       upstream_canary_(false), router_sent_end_stream_(false), encode_trailers_(false),
89:       retried_(false), awaiting_headers_(true), outlier_detection_timeout_recorded_(false),
90:       create_per_try_timeout_on_request_complete_(false), paused_for_connect_(false),
91:       paused_for_websocket_(false), reset_stream_(false),
92:       record_timeout_budget_(parent_.cluster()->timeoutBudgetStats().has_value()),
93:       cleaned_up_(false), had_upstream_(false),
94:       stream_options_({can_send_early_data, can_use_http3}), grpc_rq_success_deferred_(false),
95:       enable_half_close_(enable_half_close) {
96:   if (auto tracing_config = parent_.callbacks()->tracingConfig(); tracing_config.has_value()) {
97:     if (tracing_config->spawnUpstreamSpan() || parent_.config().start_child_span_) {
98:       span_ = parent_.callbacks()->activeSpan().spawnChild(
99:           tracing_config.value().get(),
100:           absl::StrCat("router ", parent.cluster()->observabilityName(), " egress"),
101:           parent_.callbacks()->dispatcher().timeSource().systemTime());
102:       if (parent.attemptCount() != 1) {
103:         // This is a retry request, add this metadata to span.
104:         span_->setTag(Tracing::Tags::get().RetryCount, std::to_string(parent.attemptCount() - 1));
105:       }
106:     }
107:   }
108: 
109:   // The router checks that the connection pool is non-null before creating the upstream request.
110:   auto upstream_host = conn_pool_->host();
111:   Tracing::HttpTraceContext trace_context(*parent_.downstreamHeaders());
112:   Tracing::UpstreamContext upstream_context(upstream_host.get(),           // host_
113:                                             &upstream_host->cluster(),     // cluster_
114:                                             Tracing::ServiceType::Unknown, // service_type_
115:                                             false                          // async_client_span_
116:   );
117: 
118:   if (span_ != nullptr) {
119:     span_->injectContext(trace_context, upstream_context);
120:   } else {
121:     // No independent child span for current upstream request then inject the parent span's tracing
122:     // context into the request headers.
123:     // The injectContext() of the parent span may be called repeatedly when the request is retried.
124:     parent_.callbacks()->activeSpan().injectContext(trace_context, upstream_context);
125:   }
126: 
127:   stream_info_.setUpstreamInfo(std::make_shared<StreamInfo::UpstreamInfoImpl>());
128:   stream_info_.route_ = parent_.callbacks()->route();
129:   stream_info_.upstreamInfo()->setUpstreamHost(upstream_host);
130:   parent_.callbacks()->streamInfo().setUpstreamInfo(stream_info_.upstreamInfo());
131: 
132:   stream_info_.healthCheck(parent_.callbacks()->streamInfo().healthCheck());
133:   stream_info_.setIsShadow(parent_.callbacks()->streamInfo().isShadow());
134:   absl::optional<Upstream::ClusterInfoConstSharedPtr> cluster_info =
135:       parent_.callbacks()->streamInfo().upstreamClusterInfo();
136:   if (cluster_info.has_value()) {
137:     stream_info_.setUpstreamClusterInfo(*cluster_info);
138:   }
139: 
140:   // Set up the upstream HTTP filter manager.
141:   filter_manager_callbacks_ = std::make_unique<UpstreamRequestFilterManagerCallbacks>(*this);
142:   filter_manager_ = std::make_unique<UpstreamFilterManager>(
143:       *filter_manager_callbacks_, parent_.callbacks()->dispatcher(), UpstreamRequest::connection(),
144:       parent_.callbacks()->streamId(), parent_.callbacks()->account(), true,
145:       parent_.callbacks()->decoderBufferLimit(), *this);
146:   // Attempt to create custom cluster-specified filter chain
147:   bool created = filter_manager_->createFilterChain(*parent_.cluster()).created();
148: 
149:   if (!created) {
150:     // Attempt to create custom router-specified filter chain.
151:     created = filter_manager_->createFilterChain(parent_.config()).created();
152:   }
153:   if (!created) {
154:     // Neither cluster nor router have a custom filter chain; add the default
155:     // cluster filter chain, which only consists of the codec filter.
156:     created = filter_manager_->createFilterChain(defaultUpstreamHttpFilterChainFactory()).created();
157:   }
158:   // There will always be a codec filter present, which sets the upstream
159:   // interface. Fast-fail any tests that don't set up mocks correctly.
160:   ASSERT(created && upstream_interface_.has_value());
161: }
